+// reloadStatusTracker stores the last completed transactional reload. Persistence
+// is deliberately best-effort: an unreadable status file must never stop startup.
+type reloadStatusTracker struct {
+	mu       sync.RWMutex
+	path     string
+	status   api_v1.ReloadStatus
+}
