+func newReloadStatusTracker(dir string) *reloadStatusTracker {
+	t := &reloadStatusTracker{
+		path: filepath.Join(dir, reloadStatusFilename),
+		status: api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}},
+	}
+	b, err := os.ReadFile(t.path)
+	if err != nil {
+		return t
+	}
+	var status api_v1.ReloadStatus
+	if json.Unmarshal(b, &status) == nil {
+		if status.AppliedReloaders == nil {
+			status.AppliedReloaders = []string{}
+		}
+		if status.ReloaderTimingsMS == nil {
+			status.ReloaderTimingsMS = map[string]int64{}
+		}
+		t.status = status
+	}
+	return t
+}
+
+func (t *reloadStatusTracker) Get() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	s := t.status
+	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]int64, len(s.ReloaderTimingsMS))
+	for k, v := range t.status.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[k] = v
+	}
+	return s
+}
+
+func (t *reloadStatusTracker) Record(status api_v1.ReloadStatus) {
+	t.mu.Lock()
+	defer t.mu.Unlock()
+	t.status = status
+	b, err := json.Marshal(status)
+	if err != nil {
+		return
+	}
+	// Rename makes a completed outcome durable without exposing a partial JSON file.
+	tmp := t.path + ".tmp"
+	if os.WriteFile(tmp, b, 0o644) == nil {
+		_ = os.Rename(tmp, t.path)
