+
+// reloadConfigTransactional stops at the first failed component and restores the
+// complete last known-good configuration when a partial apply occurred. Initial
+// configuration loading establishes that known-good configuration but is not a
+// reload attempt and therefore is intentionally not recorded.
+func reloadConfigTransactional(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), tracker *reloadStatusTracker, lastGood **config.Config, initial bool, rls ...reloader) (err error) {
+	start := time.Now()
+	status := api_v1.ReloadStatus{
+		LastReloadID:      start.UTC().Format(time.RFC3339Nano),
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	}
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		if !initial {
+			status.LastReloadSuccessful = err == nil
+			if err != nil && status.ErrorMessage == "" {
+				status.ErrorMessage = err.Error()
+			}
+			tracker.Record(status)
+		}
+	}()
+
+	logger.Info("Loading configuration file", "filename", filename)
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		status.ErrorCategory = "load_error"
+		status.ErrorMessage = err.Error()
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	for _, rl := range rls {
+		rstart := time.Now()
+		rerr := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(rstart))
+		if rerr != nil {
+			status.ErrorCategory = "apply_error"
+			status.ErrorMessage = rerr.Error()
+			status.FailedReloader = rl.name
+			// A failure before any component was changed leaves the old config intact.
+			if len(status.AppliedReloaders) > 0 && *lastGood != nil {
+				status.RollbackAttempted = true
+				status.RollbackSuccessful = true
+				for _, rollback := range rls {
+					if rollbackErr := rollback.reloader(*lastGood); rollbackErr != nil {
+						status.RollbackSuccessful = false
+						status.ErrorCategory = "rollback_error"
+						status.ErrorMessage = rollbackErr.Error()
+						status.FailedReloader = rollback.name
+					}
+				}
+			}
+			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, rerr)
+		}
+		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	*lastGood = conf
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
